VALUES
  ('cpa-moex-01071', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '以預計成本分攤服務部門的成本給使用部門，較以實際成本分攤的優點可能包括：①只需要使用一', '["只需要一個成本庫", "使用部門可預先得知分攤費率，減少不確定性", "服務部門無法將無效率與浪費的成本轉嫁。上述何者正確？", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01072', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '大力士公司在海外設廠生產聯產品；其中一項稱為Strong的產品計有100單位，可在分離點立即出 售，亦可選擇繼續加工後變成一種酒精飲料，以售價$120賣出，但須同時支付飲料售價的20%作為 菸酒稅。分攤到Strong之聯合成本為$2,000，已知繼續加工所需成本為$1,600。試問：Strong產品在 分離點訂定售價為多少時，將使繼續加工與不加工在利潤上並無差異？', '["$120", "$100", "$90", "$80"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01073', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '大安公司由同一製程生產了M、N兩種聯產品，兩者在分離點後之加工總成本為$60,000，加工後M 和N之銷售價值合計數為$150,000，其餘有關資料如下： M產品  N產品 分攤之聯合成本  ？  $20,400 分離點後之個別成本  $30,000  ？ 最終售價  ？  $60,000 該公司對於聯合成本之分攤採市價法，且假設各產品之毛利率固定。試問：經分攤聯合成本後，M 產品之總生產成本為何？', '["$75,600", "$44,000", "$45,600", "$60,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01074', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '內湖公司提供明年銷貨預算前四個月的資料如下： 月  份  預計銷貨額 一月  $240,000 二月  $216,000 三月  $264,000 四月  $288,000 銷貨毛利率為 40%。今年底存貨為$43,200，且每月月底應維持的期末存貨額為下個月銷貨所需的 30%。請問：二月份的商品採購預算金額為何？', '["$138,240", "$120,960", "$230,400", "$129,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01075', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司生產單一產品並使用實際成本制度。其成本資訊如下：生產量100,000單位，銷售量80,000單 位，單位售價$20，機器小時50,000，直接材料$80,000，直接人工$240,000，變動製造費用$40,000， 固定製造費用$200,000，變動銷售費用$48,000，固定銷售費用$20,000，假設沒有期初存貨，試問下 列何者正確？', '["相較於歸納成本法（absorption costing），採用變動成本法（variable costing）所計算的單位成本與 淨利都較低", "相較於歸納成本法（absorption costing），採用變動成本法（variable costing）所計算的單位成本與 淨利都較高", "相較於歸納成本法（absorption costing），採用變動成本法（variable costing）所計算的單位成本較 低且淨利較高", "相較於歸納成本法（absorption costing），採用變動成本法（variable costing）所計算的單位成本較 高且淨利較低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01076', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '遠見公司在X1年共銷售 12,000單位的產品，每單位平均售價$20、直接材料$4、直接人工$1.6、 變動製造費用$0.4、變動銷售成本$2，每年的固定成本有$12,000與銷售活動相關，有$84,000與銷售 活動無關。預計公司在X2年直接材料成本與直接人工成本變化後，營運槓桿為5。假設其他情況 不變，則該公司的邊際貢獻（contribution margin）將較X1年增加或減少多少？', '["增加$24,000", "增加$14,000", "減少$14,000", "減少$24,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01077', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列敘述中，何者錯誤？①當某產品的實際銷售組合比例較預計銷售組合比例低時，則該產品將產', '["當獲利性較低之產品的實際銷售比例較預計銷售比 例低時，公司整體將會產生不利的銷售組合差異", "當經濟景氣好轉時，可能產生有利的市場規模 差異（market-size variance）", "公司管理者應對不利的市場規模差異負責", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01078', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '有關銷貨差異分析之敘述，下列何者正確？①銷售價格差異（selling-price variance）可區分為彈性預', '["彈性預算差異可區分 為銷售組合差異（sales-mix variance）與銷售數量差異", "靜態預算差異（static-budget variance）可 區分為彈性預算差異與純銷售數量差異（sales-quantity variance）", "銷售數量差異可區分為銷售組 合差異與純銷售數量差異", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01079', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '大直公司有兩個部門，A部門銷售豆粉給B部門，B部門再以每公斤$5出售製成品「豆乳」給顧客。 A部門成本每公斤$0.75，其內部轉撥價格訂為每公斤$1.25，而B部門另外發生成本每公斤$2.50來 完成其製造與銷售，則大直公司每公斤的營業利潤是多少？', '["$1.75", "$1.25", "$0.50", "$0"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01080', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '雲飛公司產銷甲、乙二種產品，各產品每單位售價及變動成本如下： 產品  甲  乙 售價  $12  $15 變動成本  6  7 雲飛公司之生產能量有限，每月僅有2,000機器小時可資利用，生產一單位甲需耗3機器小時，而生 產一單位乙需耗2機器小時。 又雲飛公司技術工人有限，每月僅有1,500人工小時可資利用，生產一單位甲需耗2人工小時，而生 產一單位乙需耗4人工小時，則雲飛公司每月最大之邊際貢獻是多少？', '["$4,846", "$4,246", "$3,646", "$3,046"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
